var __index = {"config":{"lang":["en"],"separator":"[\\s\\u200b\\-_,:!=\\[\\]()\"`/]+|\\.(?!\\d)|&[lg]t;|(?!\\b)(?=[A-Z][a-z])","pipeline":["stemmer"]},"docs":[{"location":"index.html","title":"\u4e3b\u9875","text":""},{"location":"index.html#avalontips","title":"\u6b22\u8fce\u6765\u5230 avalontips\uff01","text":"<p>\u8fd9\u4efd\u6587\u6863\u662f\u7528\u6765\u505a\u4ec0\u4e48\u7684?</p> <p>\u89e3\u7b54\u4e00\u4e9b\u5bf9\u4e8e Avalonia \u5f00\u53d1\u7684\u5e38\u89c1\u95ee\u9898\uff0c\u63d0\u4f9b\u6280\u5de7\uff0c\u5e76\u5206\u4eab\u7ecf\u9a8c\u3002</p> <p>Info</p> <p>\u672c\u6587\u6863\u5047\u5b9a\u4f60\u6709\u4e00\u4e9b\u57fa\u7840\u7684 .NET \u5f00\u53d1\u77e5\u8bc6\uff0c\u5982\u679c\u4f60\u662f\u65b0\u624b\uff0c\u5efa\u8bae\u5148\u5b66\u4e60\u4e00\u4e9b\u57fa\u7840\u77e5\u8bc6\u3002 \u5982\u679c\u4f60\u6709 WPF \u7684\u76f8\u5173\u5f00\u53d1\u7ecf\u9a8c\uff0c\u90a3\u4e48\u4f1a\u66f4\u597d\u3002</p>"},{"location":"basic/index.html","title":"\u5199\u5728\u524d\u9762\u7684","text":"<p>Warning</p> <p>Avalonia \u4e0d\u662f WPF \u7684\u4e00\u4e2a\u514b\u9686\u3002\u867d\u7136\u5b83\u7684 API \u4e0e WPF \u76f8\u4f3c\uff0c\u4f46\u5b83\u662f\u4ece\u5934\u5f00\u59cb\u6784\u5efa\u7684\uff0c\u56e0\u6b64\u6709\u4e00\u4e9b\u4e0d\u540c\u4e4b\u5904\u3002</p> <p>\u4e3a\u4ec0\u4e48\u6211\u5728X\u4e2d\u53ef\u4ee5\u4f46\u662f\u5728Avalonia\u4e2d\u4e0d\u884c\uff1f</p> <p>Avalonia \u4e0d\u662f\u4efb\u4f55\u5176\u4ed6\u6846\u67b6\u7684\u514b\u9686\uff0c\u5982\u679c\u4f60\u60f3\u5728 Avalonia \u4e2d\u5b9e\u73b0\u67d0\u4e9b\u529f\u80fd\uff0c\u4f60\u53ef\u80fd\u9700\u8981\u91cd\u65b0\u8003\u8651\u4f60\u7684\u65b9\u6cd5\u3002\u6b64\u5904\u6709\u4e00\u4e9b Avalonia \u7684\u5e93\u548c\u6700\u4f73\u5b9e\u8df5\u3002</p>"},{"location":"basic/install.html","title":"\u5b89\u88c5","text":""},{"location":"basic/install.html#_2","title":"\u9009\u62e9\u5f00\u53d1\u5de5\u5177","text":"<p>Info</p> <p>\u5efa\u8bae\u65b0\u624b\u4f7f\u7528 IDE \u8fdb\u884c\u5f00\u53d1\uff0c\u800c\u4e0d\u662f\u4f7f\u7528\u672a\u7ecf\u914d\u7f6e\u7684\u6587\u672c\u7f16\u8f91\u5668\u5982 Visual Studio Code\u3002 IDE \u63d0\u4f9b\u66f4\u597d\u7684\u5f00\u53d1\u4f53\u9a8c\uff0c\u5305\u62ec\u4ee3\u7801\u8865\u5168\u3001\u4ee3\u7801\u63d0\u793a\u548c\u8c03\u8bd5\u529f\u80fd\u3002\u82b1\u8d39\u8fc7\u591a\u65f6\u95f4\u914d\u7f6e\u5de5\u5177\u53ef\u80fd\u4f1a\u964d\u4f4e\u5b66\u4e60\u7f16\u7a0b\u7684\u5174\u8da3\u3002</p> <p>\u4e3a\u4ec0\u4e48\u9884\u89c8\u5668\u6ca1\u6709\u6b63\u5e38\u5de5\u4f5c\uff1f</p> <p>\u8bf7\u53c2\u9605 \u9884\u89c8\u5668</p> <p>Info</p> <p>\u76ee\u524d Avalonia \u5b98\u65b9\u6ca1\u6709\u63a8\u51fa\u8bbe\u8ba1\u5668\uff08\u4f60\u53ef\u80fd\u60f3\u8981\u7c7b\u4f3c\u4e8e Visual Studio WPF \u8bbe\u8ba1\u5668\u7684\u529f\u80fd\uff09\uff0c\u5b98\u65b9\u76ee\u524d\u6b63\u5728\u5f00\u53d1\u4e2d\uff0c\u8be6\u60c5\u67e5\u770b Request for feedback - Avalonia Accelerate \ud83d\ude80\u3002 TL;DR: \u9700\u8981\u4e00\u5c0f\u7b14\u8d39\u7528\u624d\u80fd\u4f7f\u7528 Avalonia Accelerate\uff0c\u5efa\u8bae\u652f\u6301\u5f00\u6e90\u9879\u76ee\u3002</p>"},{"location":"basic/install.html#jetbrains-rider","title":"JetBrains Rider","text":"<p>\u81ea 2023.3 \u7248\u672c\u5f00\u59cb JetBrains Rider \u5185\u7f6e\u652f\u6301 Avalonia XAML</p> <p>\u5efa\u8bae\u5b89\u88c5\u9002\u7528\u4e8eAvalonia\u5f00\u53d1\u7684Rider\u63d2\u4ef6 AvaloniaRider </p>"},{"location":"basic/install.html#visual-studio","title":"Visual Studio","text":"<p>\u5982\u679c\u60a8\u6b63\u5728\u4f7f\u7528 Visual Studio \u5f00\u53d1 Avalonia\uff0c\u60a8\u5e94\u8be5\u5b89\u88c5 Avalonia for Visual Studio \u6269\u5c55\u3002</p> <ul> <li>\u5728 Visual Studio \u4e2d\uff0c\u70b9\u51fb\u6269\u5c55\u83dc\u5355\u4e0a\u7684\u7ba1\u7406\u6269\u5c55</li> <li>\u5728\u641c\u7d22\u6846\u4e2d\uff0c\u8f93\u5165\"Avalonia\"</li> <li>\u70b9\u51fb\u4e0b\u8f7d\u5e76\u6309\u7167\u8bf4\u660e\u8fdb\u884c\u64cd\u4f5c\uff08\u60a8\u9700\u8981\u5173\u95edVisual Studio\u4ee5\u5b8c\u6210\u5b89\u88c5\uff09</li> </ul> <p>Tips</p> <p>\u8003\u8651\u5230\u90e8\u5206\u5730\u533a\u7684\u7f51\u7edc\u73af\u5883\uff0c\u4f60\u53ef\u80fd\u65e0\u6cd5\u5728 Visual Studio \u4e2d\u76f4\u63a5\u5b89\u88c5 Avalonia for Visual Studio \u6269\u5c55\u3002\u4f60\u53ef\u4ee5\u901a\u8fc7 Visual Studio Marketplace \u4e0b\u8f7d <code>.vsix</code> \u6587\u4ef6\uff0c\u7136\u540e\u5728 Visual Studio \u4e2d\u901a\u8fc7 <code>\u6269\u5c55</code> -&gt; <code>\u7ba1\u7406\u6269\u5c55</code> -&gt; <code>\u4ece\u6587\u4ef6\u5b89\u88c5</code> \u5b89\u88c5\u3002</p>"},{"location":"basic/install.html#_3","title":"\u914d\u7f6e\u6a21\u677f","text":"<p>\u5728\u5b89\u88c5\u6a21\u677f\u524d\uff0c\u8bf7\u786e\u4fdd\u4f60\u5df2\u6b63\u786e\u5b89\u88c5 .NET SDK</p>"},{"location":"basic/install.html#_4","title":"\u5b89\u88c5\u6a21\u677f","text":"<p>\u8981\u5b89\u88c5 Avalonia \u6a21\u677f\uff0c\u8bf7\u8fd0\u884c\u4ee5\u4e0b\u547d\u4ee4\uff1a</p> Bash<pre><code>dotnet new install Avalonia.Templates\n</code></pre> <p>Note</p> <p>\u5bf9\u4e8e .NET 6.0 \u53ca\u66f4\u65e9\u7248\u672c\uff0c\u8bf7\u5c06<code>install</code>\u66ff\u6362\u4e3a<code>--install</code></p>"},{"location":"basic/install.html#_5","title":"\u66f4\u65b0\u6a21\u677f","text":"<p>\u5982\u679c\u4ee5\u524d\u5b89\u88c5\u8fc7\u6a21\u677f\uff0c\u4f46\u60f3\u5b89\u88c5\u6700\u65b0\u7248\u672c\uff0c\u53ef\u4ee5\u4f7f\u7528 dotnet new update \u66f4\u65b0\u5df2\u5b89\u88c5\u7684\u6a21\u677f\u3002</p> Bash<pre><code>dotnet new update\n</code></pre>"},{"location":"basic/install.html#_6","title":"\u5378\u8f7d\u6a21\u677f","text":"Bash<pre><code>dotnet new uninstall Avalonia.Templates\n</code></pre>"},{"location":"blog/index.html","title":"\u535a\u5ba2","text":""}]}